function clickLogin2() {
    console.log('[CLICKLOGIN2] Called');
    if (typeof ptzLog === 'function') ptzLog('WASM SDK 登录开始...', 'debug');
    if (!window.connectedDevice || !window.connectedDevice.ip) {
        console.log('[WASM SDK] No device connected');
        if (typeof ptzLog === 'function') ptzLog('未连接设备，无法登录', 'warning');
        return;
    }
    console.log('[CLICKLOGIN2] Device IP: ' + window.connectedDevice.ip);
    if (typeof ptzLog === 'function') ptzLog('连接设备: ' + window.connectedDevice.ip, 'info');
    var szIP = window.connectedDevice.ip;
    var szPort = window.connectedDevice.port || 80;
    var szUsername = window.connectedDevice.username || 'admin';
    var szPassword = window.connectedDevice.password || '';
    g_szDeviceIdentify2 = szIP + '_' + szPort;
    console.log('[WASM SDK] Login: ' + szIP + ':' + szPort);
    WebVideoCtrl.I_Login(szIP, 1, szPort, szUsername, szPassword, {
        timeout: 5000,
        success: function(xmlDoc) {
            g_bLoggedIn2 = true;
            console.log('[WASM SDK] Login success: ' + g_szDeviceIdentify2);
            if (typeof ptzLog === 'function') ptzLog('✅ 登录成功', 'success');
            // Step 2.1: I_GetDevicePort - get WebSocket port
            var oPort = WebVideoCtrl.I_GetDevicePort(g_szDeviceIdentify2);
            console.log('[WASM SDK] GetDevicePort result:', oPort);
            if (oPort) {
                g_iRtspPort2 = oPort.iRtspPort || 554;
                g_iWebSocketPort = oPort.iWebSocketPort || 7681; // WebSocket port for video
                if (typeof ptzLog === 'function') ptzLog('WebSocket端口: ' + g_iWebSocketPort + ', RTSP端口: ' + g_iRtspPort2, 'info');
                console.log('[WASM SDK] WebSocket port:', g_iWebSocketPort, 'RTSP port:', g_iRtspPort2);
            }
            // Step 2.2: I_GetAnalogChannelInfo - get channel list
            WebVideoCtrl.I_GetAnalogChannelInfo(g_szDeviceIdentify2, {
                success: function(xmlDocChannels) {
                    var channels = [];
                    var nodeList = xmlDocChannels.getElementsByTagName('VideoInputChannel');
                    for (var i = 0; i < nodeList.length; i++) {
                        var id = nodeList[i].getElementsByTagName('id')[0]?.textContent || (i + 1);
                        var name = nodeList[i].getElementsByTagName('name')[0]?.textContent || ('通道' + id);
                        channels.push({ id: parseInt(id), name: name });
                    }
                    g_iChannelList = channels;
                    g_iChannelID = channels.length > 0 ? channels[0].id : 1;
                    console.log('[WASM SDK] Channels:', channels, 'Using channelID:', g_iChannelID);
                    if (typeof ptzLog === 'function') ptzLog('获取通道: ' + channels.length + '个, 使用ID: ' + g_iChannelID, 'info');
                    // Step 2.3: Start stream after channel info loaded
                    console.log('[WASM SDK] Calling startConsoleStream2 in 300ms...');
                    setTimeout(function() {
                        console.log('[WASM SDK] setTimeout fired, startConsoleStream2 exists:', typeof window.startConsoleStream2);
                        if (window.startConsoleStream2) {
                            window.startConsoleStream2('sub');
                        } else {
                            console.error('[WASM SDK] startConsoleStream2 not found!');
                            if (typeof ptzLog === 'function') ptzLog('startConsoleStream2 未定义', 'error');
                        }
                    }, 300);
                },
                error: function(status, xmlDocErr) {
                    console.warn('[WASM SDK] GetAnalogChannelInfo failed:', status);
                    if (typeof ptzLog === 'function') ptzLog('获取通道失败，使用默认ID: 1', 'warning');
                    g_iChannelID = 1;
                    // Still try to start stream
                    setTimeout(function() {
                        if (window.startConsoleStream2) window.startConsoleStream2('sub');
                    }, 300);
                }
            });
        },
        error: function(status, xmlDoc) {
            console.error('[WASM SDK] Login failed:', status);
            g_bLoggedIn2 = false;
            if (typeof ptzLog === 'function') ptzLog('❌ 登录失败: ' + status, 'error');
        }
    });
}

