function startConsoleStream2(mode) {
    console.log("[STARTSTREAM2] Called, g_bLoggedIn2=", g_bLoggedIn2);
    if (typeof ptzLog === 'function') ptzLog('正在启动视频流...', 'info');
    if (!window.connectedDevice || !window.connectedDevice.ip) { console.log("[STARTSTREAM2] No device"); if (typeof ptzLog === 'function') ptzLog('未连接设备', 'warning'); return; }
    if (!g_bLoggedIn2) { if (window.clickLogin2) window.clickLogin2(); return; }
    var iStreamType = (mode === 'main') ? 1 : 2;
    var iChannelID = g_iChannelID || 1; // Use channel ID from I_GetAnalogChannelInfo
    console.log('[WASM SDK] Stream type:', iStreamType, 'Channel ID:', iChannelID);
    if (typeof ptzLog === 'function') ptzLog('码流类型: ' + (iStreamType === 1 ? '主码流' : '子码流') + ', 通道ID: ' + iChannelID, 'info');
    var oWndInfo = WebVideoCtrl.I_GetWindowStatus(g_iWndIndex2);
    var doStart = function() {
        console.log('[WASM SDK] Starting real play, stream=' + iStreamType + ', channel=' + iChannelID);
        WebVideoCtrl.I_StartRealPlay(g_szDeviceIdentify2, {
              // iRtspPort not needed for WebSocket proxy mode
            iStreamType: iStreamType,
            iChannelID: iChannelID,
            bZeroChannel: false,
            success: function() {
                g_bPlaying2 = true;
                console.log('[WASM SDK] Real play started');
                if (typeof ptzLog === 'function') ptzLog('✅ 视频播放中', 'success');
            },
            error: function(status, xmlDoc) {
                console.error('[WASM SDK] StartRealPlay error:', status);
                  if (typeof ptzLog === 'function') ptzLog('视频播放错误: ' + status, 'error');
            }
        });
    };
    if (oWndInfo != null) {
        WebVideoCtrl.I_Stop({ success: function() { doStart(); }, error: function() { doStart(); } });
    } else {
        doStart();
    }
}

