fetch('/ISAPI/Security/token?format=json', {credentials: 'include'})
    .then(r => {
        console.log('[WASM SDK] Token response status:', r.status);
        return r.text();
    })
    .then(text => {
        console.log('[WASM SDK] Token response text:', text);
        if (text) {
            const data = JSON.parse(text);
            const szAuth = data.Token?.value;
            console.log('[WASM SDK] szAuth fetched:', szAuth);
            if (szAuth) {
                // 设置到设备对象
                var deviceIdx = WebVideoCtrl.findDeviceIndexByIP(g_szDeviceIdentify2);
                if (deviceIdx >= 0) {
                    WebVideoCtrl.w_deviceSet[deviceIdx].szAuth = szAuth;
                    console.log('[WASM SDK] szAuth set to device:', szAuth);
                }
            }
        }
    })
    .catch(e => console.error('[WASM SDK] Failed to fetch szAuth:', e));

